// 来場予約メール本文から各項目を抽出
const t = String($json.text || $json.snippet || $json.html || '');
const pick = (re) => { const m = t.match(re); return m ? m[1].trim() : ''; };
const inquiry = {
  name:     pick(/お名前[:：]\s*([^\n■]+?)\s*(?:■|$)/),
  email:    pick(/メール[:：]\s*([^\s\n■]+)/),
  tel:      pick(/電話番号[:：]\s*([^\s\n■]+)/),
  area:     pick(/事業所[:：]\s*([^\n■]+?)\s*(?:■|$)/),
  hopeDate: pick(/希望日[:：]\s*([^\n■]+?)\s*(?:■|$)/),
  hopeTime: pick(/希望時間[:：]\s*([^\n■]+?)\s*(?:■|$)/),
  note:     pick(/備考[:：]\s*([^\n■—]+?)\s*(?:■|—|$)/),
  source:   'サイト予約フォーム',
  type:     '来場予約',
  receivedAt: String($json.date || '')
};
return [{ json: { inquiry } }];
